using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public required string Subject { get; set; }
    public required string Description { get; set; }
    public int Priority { get; set; } = 2;
}

public class TicketResponse
{
    public required string PredictedCategory { get; set; }
    public required Dictionary<string, float> Confidence { get; set; }
}

using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public static class TicketModelTrainer
{
    public static string[] TrainAndEvaluate(string dataPath, string modelPath)
    {
        var mlContext = new MLContext(seed: 42);

        var data = mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = mlContext.Transforms.Conversion
            .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy())
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        Console.WriteLine("Training ticket classifier model...");
        var model = pipeline.Fit(split.TrainSet);

        // Evaluate on held-out test set
        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions);

        Console.WriteLine("╔══════════════════════════════════════╗");
        Console.WriteLine("║     Model Evaluation Metrics         ║");
        Console.WriteLine("╠══════════════════════════════════════╣");
        Console.WriteLine($"║  MacroAccuracy:    {metrics.MacroAccuracy,14:F4}  ║");
        Console.WriteLine($"║  MicroAccuracy:    {metrics.MicroAccuracy,14:F4}  ║");
        Console.WriteLine($"║  LogLoss:          {metrics.LogLoss,14:F4}  ║");
        Console.WriteLine($"║  LogLossReduction: {metrics.LogLossReduction,14:F4}  ║");
        Console.WriteLine("╚══════════════════════════════════════╝");

        // Extract label-to-index mapping from the Score column's slot names
        var outputSchema = model.GetOutputSchema(data.Schema);
        var scoreColumn = outputSchema["Score"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        scoreColumn.GetSlotNames(ref slotNames);
        var values = slotNames.DenseValues().Select(v => v.ToString()).ToArray();

        mlContext.Model.Save(model, data.Schema, modelPath);
        Console.WriteLine($"Model saved to {modelPath}");

        return values;
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController : ControllerBase
{
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _predictionPool;
    private readonly string[] _labels;

    public TicketClassifierController(
        PredictionEnginePool<TicketData, TicketPrediction> predictionPool,
        ModelMetadata metadata)
    {
        _predictionPool = predictionPool;
        _labels = metadata.Labels;
    }

    [HttpPost("classify")]
    public ActionResult<TicketResponse> Classify([FromBody] TicketRequest request)
    {
        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < _labels.Length && i < prediction.Score.Length; i++)
        {
            confidence[_labels[i]] = prediction.Score[i];
        }

        return Ok(new TicketResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        });
    }
}

